// frontend/src/submit.js

// Build a cleaned payload: remove helper nodes, filter edges, compute counts and DAG flag
function buildCleanGraphPayload(nodes = [], edges = [], options = {}) {
  const excludeTypes = options.excludeTypes || ["deleteNode"];

  // 1) keep only nodes backend should see
  const keptNodes = nodes.filter((n) => !excludeTypes.includes(n.type));

  // 2) build a set of kept node ids
  const keptIds = new Set(keptNodes.map((n) => n.id));

  // 3) filter edges so both ends exist in keptIds
  const keptEdges = edges.filter((e) => keptIds.has(e.source) && keptIds.has(e.target));

  // 4) compute DAG boolean using topological sort
  const isDAG = checkIsDAG(keptNodes, keptEdges);

  return {
    nodes: keptNodes,
    edges: keptEdges,
    counts: { nodes: keptNodes.length, edges: keptEdges.length },
    dag: isDAG,
  };
}

// Topological sort / cycle detection
function checkIsDAG(nodes = [], edges = []) {
  const adj = new Map();
  const indeg = new Map();

  nodes.forEach((n) => {
    adj.set(n.id, []);
    indeg.set(n.id, 0);
  });

  edges.forEach((e) => {
    if (!adj.has(e.source) || !adj.has(e.target)) return;
    adj.get(e.source).push(e.target);
    indeg.set(e.target, (indeg.get(e.target) || 0) + 1);
  });

  const q = [];
  for (const [id, d] of indeg.entries()) if (d === 0) q.push(id);

  let visited = 0;
  while (q.length) {
    const u = q.shift();
    visited++;
    for (const v of adj.get(u) || []) {
      indeg.set(v, indeg.get(v) - 1);
      if (indeg.get(v) === 0) q.push(v);
    }
  }

  return visited === nodes.length;
}

// ============================================
// NEW: CONDITION EXECUTION ENGINE
// ============================================

// Evaluate a single condition
function evaluateCondition(operator, leftValue, rightValue) {
  console.log(`Evaluating: ${leftValue} ${operator} ${rightValue}`);

  // Convert values - try numbers first, then strings
  const left = isNaN(Number(leftValue)) ? String(leftValue) : Number(leftValue);
  const right = isNaN(Number(rightValue)) ? String(rightValue) : Number(rightValue);

  switch(operator) {
    case '==': return left == right;
    case '!=': return left != right;
    case '>': return left > right;
    case '<': return left < right;
    case '>=': return left >= right;
    case '<=': return left <= right;
    default: return false;
  }
}

// Find all input nodes and assign test values
function assignTestValues(nodes) {
  const inputValues = {};

  nodes.forEach(node => {
    if (node.type === 'inputNode') {
      // Use the inputName or a default test value
      const value = node.data?.inputName || `test_${node.id}`;
      const type = node.data?.inputType || 'Text';

      // Assign appropriate test value based on type
      if (type === 'Number') {
        inputValues[node.id] = Math.floor(Math.random() * 100) + 1; // Random 1-100
      } else if (type === 'File') {
        inputValues[node.id] = `file_${node.id}.txt`;
      } else {
        inputValues[node.id] = value;
      }
    }
  });

  return inputValues;
}

// Simulate pipeline execution with condition evaluation
function simulatePipelineExecution(nodes, edges, inputValues) {
  const executionResults = [];
  const conditionNodes = nodes.filter(n => n.type === 'conditionNode');

  // Build adjacency list
  const adjacency = new Map();
  nodes.forEach(n => adjacency.set(n.id, []));
  edges.forEach(e => {
    if (adjacency.has(e.source)) {
      adjacency.get(e.source).push({ target: e.target, handle: e.targetHandle });
    }
  });

  // Process each condition node
  conditionNodes.forEach(conditionNode => {
    const nodeId = conditionNode.id;
    const operator = conditionNode.data?.operator || '==';
    const compareValue = conditionNode.data?.value || '';

    // Find input edges to this condition
    const inputEdges = edges.filter(e => e.target === nodeId);

    if (inputEdges.length >= 1) {
      // Get the first input value (simplified - real would need both inputs)
      const inputEdge = inputEdges[0];
      const inputNodeId = inputEdge.source;
      const leftValue = inputValues[inputNodeId] || `input_${inputNodeId}`;

      // Evaluate condition
      const result = evaluateCondition(operator, leftValue, compareValue);
      const outputPort = result ? 'true' : 'false';

      // Find which output node this would route to
      const outputEdges = edges.filter(e => 
        e.source === nodeId && e.sourceHandle === outputPort
      );

      const outputNodeIds = outputEdges.map(e => e.target);

      executionResults.push({
        conditionNodeId: nodeId,
        operator,
        compareValue,
        inputValue: leftValue,
        result,
        outputPort,
        wouldRouteTo: outputNodeIds,
        message: `Condition ${nodeId}: ${leftValue} ${operator} ${compareValue} = ${result} → Outputs to ${outputPort} port`
      });
    } else {
      executionResults.push({
        conditionNodeId: nodeId,
        error: 'No inputs connected',
        message: `Condition ${nodeId}: No input values provided`
      });
    }
  });

  return executionResults;
}

// Generate a readable summary
function generateExecutionSummary(executionResults) {
  if (executionResults.length === 0) {
    return "No condition nodes found in pipeline.";
  }

  let summary = "Condition Execution Results:\n";
  executionResults.forEach((result, index) => {
    summary += `\n${index + 1}. ${result.message}`;
    if (result.wouldRouteTo && result.wouldRouteTo.length > 0) {
      summary += ` → Would route to node(s): ${result.wouldRouteTo.join(', ')}`;
    }
    if (result.error) {
      summary += ` [ERROR: ${result.error}]`;
    }
  });

  return summary;
}

// ============================================
// MAIN SUBMIT FUNCTION (ENHANCED)
// ============================================

export async function submitPipeline(nodes, edges) {
  try {
    // Build a clean payload right at submit time to avoid stale or helper data
    const payload = buildCleanGraphPayload(nodes, edges, { excludeTypes: ["deleteNode"] });

    // Debug log so you can inspect what is being sent
    console.log("Submitting pipeline payload:", {
      nodeCount: payload.counts.nodes,
      edgeCount: payload.counts.edges,
      dag: payload.dag,
      nodes: payload.nodes,
      edges: payload.edges,
    });

    // NEW: Simulate condition execution
    const inputValues = assignTestValues(payload.nodes);
    const executionResults = simulatePipelineExecution(payload.nodes, payload.edges, inputValues);
    const executionSummary = generateExecutionSummary(executionResults);

    console.log("Condition Simulation:", executionResults);
    console.log(executionSummary);

    const res = await fetch("http://127.0.0.1:8000/pipelines/parse", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        nodes: payload.nodes,
        edges: payload.edges,
        // include counts and dag if backend expects them
        num_nodes: payload.counts.nodes,
        num_edges: payload.counts.edges,
        is_dag: payload.dag,
        // NEW: Include condition simulation results
        condition_results: executionResults,
        execution_summary: executionSummary,
      }),
    });

    const data = await res.json();

    // Use backend response if available, otherwise show our computed values
    const numNodes = data?.num_nodes ?? payload.counts.nodes;
    const numEdges = data?.num_edges ?? payload.counts.edges;
    const isDag = data?.is_dag ?? payload.dag;

    // NEW: Enhanced alert with condition results
    let alertMessage = `Graph Analysis:\n`;
    alertMessage += `Nodes: ${numNodes}, Edges: ${numEdges}, DAG: ${isDag ? 'Yes ✓' : 'No ✗'}\n\n`;

    if (executionResults.length > 0) {
      alertMessage += `Condition Simulation (${executionResults.length} nodes):\n`;
      executionResults.forEach((result, index) => {
        if (result.error) {
          alertMessage += `${index + 1}. ${result.conditionNodeId}: ${result.error}\n`;
        } else {
          alertMessage += `${index + 1}. ${result.conditionNodeId}: ${result.inputValue} ${result.operator} ${result.compareValue} = ${result.result ? 'TRUE' : 'FALSE'}\n`;
        }
      });
    } else {
      alertMessage += `No condition nodes to simulate.`;
    }

    // Also log detailed results to console
    console.log("Detailed condition analysis:", executionResults);

    alert(alertMessage);
  } catch (err) {
    console.error("submitPipeline error:", err);
    alert(`Error: ${err?.message || err}`);
  }
}

export const SubmitButton = ({ nodes, edges }) => (
  <button onClick={() => submitPipeline(nodes, edges)}>Submit Pipeline</button>
);
